/**
 * ReportCenterPage — Report type selection hub.
 *
 * 6 report types:
 * - 📊 老板汇报版 (Management: conclusions + ROI)
 * - 🎬 内容执行版 (Content team: topics + script directions)
 * - 📈 投放执行版 (Ad buyer: test plans + budget)
 * - 🤝 客户汇报版 (Client: evidence + strategy logic)
 * - 🎯 竞品机会版 (Market team: competitor analysis)
 * - 📅 月度复盘版 (Growth team: strategy effects + attribution)
 *
 * Click any card → opens ReportPreview with the selected type.
 */
import React, { useState } from 'react';
import {
  Box,
  Typography,
  Card,
  CardContent,
  CardActionArea,
  Grid,
  Alert,
  Chip,
} from '@mui/material';
import { useBrandStore } from '@/shared/stores/brandStore';
import ReportPreview from './ReportPreview';

interface ReportType {
  id: string;
  icon: string;
  title: string;
  subtitle: string;
  audience: string;
  color: string;
}

const REPORT_TYPES: ReportType[] = [
  {
    id: 'management',
    icon: '📊',
    title: '老板汇报版',
    subtitle: '管理层视角，聚焦结论和ROI',
    audience: '管理层',
    color: '#6366F1',
  },
  {
    id: 'content',
    icon: '🎬',
    title: '内容执行版',
    subtitle: '内容团队，含具体选题和脚本方向',
    audience: '内容团队',
    color: '#10B981',
  },
  {
    id: 'advertising',
    icon: '📈',
    title: '投放执行版',
    subtitle: '投手，含测试方案和预算建议',
    audience: '投放团队',
    color: '#F59E0B',
  },
  {
    id: 'client',
    icon: '🤝',
    title: '客户汇报版',
    subtitle: '甲方，含评论证据和策略推导',
    audience: '客户/甲方',
    color: '#EF4444',
  },
  {
    id: 'competitor',
    icon: '🎯',
    title: '竞品机会版',
    subtitle: '市场团队，竞品分析和切入机会',
    audience: '市场团队',
    color: '#8B5CF6',
  },
  {
    id: 'monthly',
    icon: '📅',
    title: '月度复盘版',
    subtitle: '增长团队，策略效果和归因分析',
    audience: '增长团队',
    color: '#EC4899',
  },
];

const ReportCenterPage: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const [selectedReport, setSelectedReport] = useState<string | null>(null);

  if (!currentBrandId) {
    return (
      <Box sx={{ p: 4, textAlign: 'center' }}>
        <Alert severity="info">请先在顶部选择一个品牌</Alert>
      </Box>
    );
  }

  if (selectedReport) {
    const reportType = REPORT_TYPES.find((r) => r.id === selectedReport);
    return (
      <ReportPreview
        reportType={reportType!}
        onBack={() => setSelectedReport(null)}
      />
    );
  }

  return (
    <Box sx={{ p: 3 }}>
      <Typography variant="h5" fontWeight={700} gutterBottom>
        📄 报告中心
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        选择报告类型，基于当前品牌已确认数据生成专业报告
      </Typography>

      <Grid container spacing={2}>
        {REPORT_TYPES.map((report) => (
          <Grid item xs={12} sm={6} md={4} key={report.id}>
            <Card
              sx={{
                height: '100%',
                transition: 'box-shadow 0.2s, transform 0.2s',
                '&:hover': { boxShadow: 6, transform: 'translateY(-2px)' },
                borderTop: `3px solid ${report.color}`,
              }}
            >
              <CardActionArea
                onClick={() => setSelectedReport(report.id)}
                sx={{ height: '100%' }}
              >
                <CardContent>
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 1.5 }}>
                    <Typography variant="h4">{report.icon}</Typography>
                    <Box>
                      <Typography variant="subtitle1" fontWeight={600}>
                        {report.title}
                      </Typography>
                      <Chip
                        label={report.audience}
                        size="small"
                        variant="outlined"
                        sx={{
                          fontSize: 10,
                          height: 20,
                          color: report.color,
                          borderColor: report.color,
                        }}
                      />
                    </Box>
                  </Box>
                  <Typography variant="body2" color="text.secondary">
                    {report.subtitle}
                  </Typography>
                </CardContent>
              </CardActionArea>
            </Card>
          </Grid>
        ))}
      </Grid>
    </Box>
  );
};

export default ReportCenterPage;
