/**
 * ReportPreview — Report content generation and preview with print/export support.
 *
 * Generates report content based on the selected report type and current brand data.
 * Sections: Brand overview, key metrics, top insights, strategy suggestions, competitor analysis.
 * Supports: window.print() + CSS @media print, Markdown export.
 */
import React, { useMemo } from 'react';
import {
  Box,
  Typography,
  Button,
  Card,
  CardContent,
  Divider,
  Chip,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Alert,
  CircularProgress,
  Stack,
} from '@mui/material';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import PrintIcon from '@mui/icons-material/Print';
import DownloadIcon from '@mui/icons-material/Download';
import { useBrandStore } from '@/shared/stores/brandStore';
import { db } from '@/shared/db/db';
import { useLiveQuery } from 'dexie-react-hooks';
import type { Insight } from '@/shared/types/insight';
import type { StrategyCard } from '@/shared/types/strategy';

interface ReportType {
  id: string;
  icon: string;
  title: string;
  subtitle: string;
  audience: string;
  color: string;
}

interface ReportPreviewProps {
  reportType: ReportType;
  onBack: () => void;
}

const ReportPreview: React.FC<ReportPreviewProps> = ({ reportType, onBack }) => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const currentBrand = useBrandStore((s) => {
    const { brands, currentBrandId: cid } = s;
    return brands.find((b) => b.id === cid) ?? null;
  });

  const insights = useLiveQuery(
    () =>
      currentBrandId
        ? db.insights.where({ brandId: currentBrandId }).toArray()
        : Promise.resolve([] as Insight[]),
    [currentBrandId],
  );

  const strategyCards = useLiveQuery(
    () =>
      currentBrandId
        ? db.strategyCards.where({ brandId: currentBrandId }).toArray()
        : Promise.resolve([] as StrategyCard[]),
    [currentBrandId],
  );

  const comments = useLiveQuery(
    () =>
      currentBrandId
        ? db.comments.where({ brandId: currentBrandId }).toArray()
        : Promise.resolve([]),
    [currentBrandId],
  );

  const confirmedInsights = useMemo(
    () => (insights ?? []).filter((i) => i.reviewStatus === 'confirmed'),
    [insights],
  );

  const confirmedStrategies = useMemo(
    () => (strategyCards ?? []).filter((s) => s.reviewStatus === 'confirmed'),
    [strategyCards],
  );

  const isLoading = insights === undefined || strategyCards === undefined || comments === undefined;

  const brandName = currentBrand?.name ?? '未命名品牌';
  const today = new Date().toLocaleDateString('zh-CN', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  const handlePrint = () => {
    window.print();
  };

  const handleExportMarkdown = () => {
    const lines: string[] = [];
    lines.push(`# ${reportType.icon} ${reportType.title} — ${brandName}`);
    lines.push(`> 生成日期：${today} | 目标受众：${reportType.audience}`);
    lines.push('');

    lines.push('## 品牌概览');
    lines.push(`- 品牌：${brandName}`);
    lines.push(`- 行业：${currentBrand?.industry ?? '未设置'}`);
    lines.push(`- 总评论数：${(comments ?? []).length}`);
    lines.push(`- 已确认洞察：${confirmedInsights.length}`);
    lines.push(`- 策略卡数：${confirmedStrategies.length}`);
    lines.push('');

    if (confirmedInsights.length > 0) {
      lines.push('## Top 洞察');
      confirmedInsights.slice(0, 10).forEach((ins, i) => {
        lines.push(`### ${i + 1}. ${ins.title}`);
        lines.push(`> 类型: ${ins.type} | 置信度: ${(ins.confidence * 100).toFixed(0)}%`);
        lines.push('');
        lines.push(ins.content);
        lines.push('');
      });
    }

    if (confirmedStrategies.length > 0) {
      lines.push('## 策略建议');
      confirmedStrategies.forEach((s, i) => {
        lines.push(`### ${i + 1}. [${s.priority}] ${s.title}`);
        lines.push(`- 内容方向：${s.contentDirection}`);
        lines.push(`- 预算建议：${s.budgetSuggestion}`);
        lines.push(`- 预期KPI：${s.expectedKPIs.join(', ')}`);
        lines.push('');
      });
    }

    if (currentBrand?.competitors && currentBrand.competitors.length > 0) {
      lines.push('## 竞品分析');
      currentBrand.competitors.forEach((c) => {
        lines.push(`### ${c.name}`);
        lines.push(`- 定位：${c.positioning}`);
        lines.push(`- 优势：${c.strengths.join(', ')}`);
        lines.push(`- 劣势：${c.weaknesses.join(', ')}`);
        lines.push('');
      });
    }

    const md = lines.join('\n');
    const blob = new Blob([md], { type: 'text/markdown;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${brandName}_${reportType.title}_${today}.md`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  if (isLoading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', py: 8 }}>
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box sx={{ p: 3, maxWidth: 900, mx: 'auto' }} className="report-preview">
      {/* Print-only styles */}
      <style>{`
        @media print {
          body * { visibility: hidden; }
          .report-preview, .report-preview * { visibility: visible; }
          .report-preview { position: absolute; left: 0; top: 0; width: 100%; padding: 20px; }
          .no-print { display: none !important; }
        }
      `}</style>

      {/* Action bar (no-print) */}
      <Stack direction="row" spacing={2} sx={{ mb: 3 }} className="no-print">
        <Button startIcon={<ArrowBackIcon />} size="small" onClick={onBack}>
          返回报告列表
        </Button>
        <Box sx={{ flexGrow: 1 }} />
        <Button variant="outlined" startIcon={<PrintIcon />} onClick={handlePrint}>
          打印 / 导出 PDF
        </Button>
        <Button variant="outlined" startIcon={<DownloadIcon />} onClick={handleExportMarkdown}>
          导出 Markdown
        </Button>
      </Stack>

      {/* Report Header */}
      <Box sx={{ mb: 4, pb: 2, borderBottom: `3px solid ${reportType.color}` }}>
        <Typography variant="h3" fontWeight={700} gutterBottom>
          {reportType.icon} {reportType.title}
        </Typography>
        <Stack direction="row" spacing={2} alignItems="center">
          <Chip
            label={`目标受众: ${reportType.audience}`}
            size="small"
            sx={{ bgcolor: reportType.color, color: '#fff' }}
          />
          <Typography variant="body2" color="text.secondary">
            生成日期：{today}
          </Typography>
        </Stack>
      </Box>

      {/* Brand Overview */}
      <Card sx={{ mb: 3 }} elevation={0} variant="outlined">
        <CardContent>
          <Typography variant="h6" fontWeight={600} gutterBottom sx={{ color: reportType.color }}>
            🏢 品牌概览
          </Typography>
          <TableContainer>
            <Table size="small">
              <TableBody>
                <TableRow>
                  <TableCell sx={{ fontWeight: 500, width: 160 }}>品牌名称</TableCell>
                  <TableCell>{brandName}</TableCell>
                </TableRow>
                <TableRow>
                  <TableCell sx={{ fontWeight: 500 }}>行业</TableCell>
                  <TableCell>{currentBrand?.industry ?? '未设置'}</TableCell>
                </TableRow>
                <TableRow>
                  <TableCell sx={{ fontWeight: 500 }}>总评论数</TableCell>
                  <TableCell>{(comments ?? []).length.toLocaleString()}</TableCell>
                </TableRow>
                <TableRow>
                  <TableCell sx={{ fontWeight: 500 }}>已确认洞察</TableCell>
                  <TableCell>{confirmedInsights.length}</TableCell>
                </TableRow>
                <TableRow>
                  <TableCell sx={{ fontWeight: 500 }}>策略卡数</TableCell>
                  <TableCell>{confirmedStrategies.length}</TableCell>
                </TableRow>
              </TableBody>
            </Table>
          </TableContainer>
        </CardContent>
      </Card>

      {/* Key Metrics */}
      <Card sx={{ mb: 3 }} elevation={0} variant="outlined">
        <CardContent>
          <Typography variant="h6" fontWeight={600} gutterBottom sx={{ color: reportType.color }}>
            📊 关键指标
          </Typography>
          <Box sx={{ display: 'flex', gap: 3, flexWrap: 'wrap' }}>
            {[
              { label: '总评论', value: (comments ?? []).length },
              {
                label: '正面评论',
                value: (comments ?? []).filter((c) => c.sentiment === 'positive').length,
              },
              {
                label: '负面评论',
                value: (comments ?? []).filter((c) => c.sentiment === 'negative').length,
              },
              { label: '需求洞察', value: confirmedInsights.filter((i) => i.type === 'demand').length },
              { label: '障碍洞察', value: confirmedInsights.filter((i) => i.type === 'barrier').length },
              { label: '竞品洞察', value: confirmedInsights.filter((i) => i.type === 'competitor').length },
            ].map((m, i) => (
              <Box key={i} sx={{ textAlign: 'center', minWidth: 100 }}>
                <Typography variant="h5" fontWeight={700} color={reportType.color}>
                  {m.value}
                </Typography>
                <Typography variant="caption" color="text.secondary">
                  {m.label}
                </Typography>
              </Box>
            ))}
          </Box>
        </CardContent>
      </Card>

      {/* Top Insights */}
      <Card sx={{ mb: 3 }} elevation={0} variant="outlined">
        <CardContent>
          <Typography variant="h6" fontWeight={600} gutterBottom sx={{ color: reportType.color }}>
            💡 Top 洞察
          </Typography>
          {confirmedInsights.length === 0 ? (
            <Alert severity="info" sx={{ mt: 1 }}>暂无已确认的洞察数据</Alert>
          ) : (
            confirmedInsights.slice(0, 10).map((ins, idx) => (
              <Box key={ins.id} sx={{ mb: 2 }}>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 0.5 }}>
                  <Chip
                    label={`#${idx + 1}`}
                    size="small"
                    sx={{ bgcolor: reportType.color, color: '#fff', fontWeight: 600 }}
                  />
                  <Typography variant="subtitle2" fontWeight={600}>
                    {ins.title}
                  </Typography>
                  <Chip
                    label={ins.type}
                    size="small"
                    variant="outlined"
                    sx={{ fontSize: 10, height: 20 }}
                  />
                  <Chip
                    label={`${(ins.confidence * 100).toFixed(0)}%`}
                    size="small"
                    color={ins.confidence >= 0.7 ? 'success' : 'warning'}
                    sx={{ fontSize: 10, height: 20 }}
                  />
                </Box>
                <Typography variant="body2" color="text.secondary" sx={{ pl: 5 }}>
                  {ins.content}
                </Typography>
                {idx < Math.min(confirmedInsights.length, 10) - 1 && (
                  <Divider sx={{ my: 1.5, ml: 5 }} />
                )}
              </Box>
            ))
          )}
        </CardContent>
      </Card>

      {/* Strategy Suggestions */}
      <Card sx={{ mb: 3 }} elevation={0} variant="outlined">
        <CardContent>
          <Typography variant="h6" fontWeight={600} gutterBottom sx={{ color: reportType.color }}>
            🎯 策略建议
          </Typography>
          {confirmedStrategies.length === 0 ? (
            <Alert severity="info" sx={{ mt: 1 }}>暂无已确认的策略卡</Alert>
          ) : (
            <TableContainer component={Paper} variant="outlined">
              <Table size="small">
                <TableHead>
                  <TableRow>
                    <TableCell sx={{ fontWeight: 600 }}>优先级</TableCell>
                    <TableCell sx={{ fontWeight: 600 }}>策略标题</TableCell>
                    <TableCell sx={{ fontWeight: 600 }}>内容方向</TableCell>
                    <TableCell sx={{ fontWeight: 600 }}>预算建议</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {confirmedStrategies.map((s) => (
                    <TableRow key={s.id}>
                      <TableCell>
                        <Chip
                          label={s.priority}
                          size="small"
                          color={
                            s.priority === 'P0'
                              ? 'error'
                              : s.priority === 'P1'
                                ? 'warning'
                                : 'primary'
                          }
                          sx={{ fontWeight: 700, height: 22 }}
                        />
                      </TableCell>
                      <TableCell>{s.title}</TableCell>
                      <TableCell>
                        {s.contentDirection.length > 60
                          ? s.contentDirection.substring(0, 60) + '...'
                          : s.contentDirection}
                      </TableCell>
                      <TableCell>{s.budgetSuggestion}</TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          )}
        </CardContent>
      </Card>

      {/* Competitor Analysis */}
      {currentBrand?.competitors && currentBrand.competitors.length > 0 && (
        <Card sx={{ mb: 3 }} elevation={0} variant="outlined">
          <CardContent>
            <Typography variant="h6" fontWeight={600} gutterBottom sx={{ color: reportType.color }}>
              🏢 竞品分析
            </Typography>
            {currentBrand.competitors.map((comp) => (
              <Box key={comp.id} sx={{ mb: 2 }}>
                <Typography variant="subtitle2" fontWeight={600} gutterBottom>
                  {comp.name}
                </Typography>
                <TableContainer component={Paper} variant="outlined" sx={{ mb: 1 }}>
                  <Table size="small">
                    <TableBody>
                      <TableRow>
                        <TableCell sx={{ fontWeight: 500, width: 80 }}>定位</TableCell>
                        <TableCell>{comp.positioning}</TableCell>
                      </TableRow>
                      <TableRow>
                        <TableCell sx={{ fontWeight: 500 }}>优势</TableCell>
                        <TableCell>{comp.strengths.join('、')}</TableCell>
                      </TableRow>
                      <TableRow>
                        <TableCell sx={{ fontWeight: 500 }}>劣势</TableCell>
                        <TableCell>{comp.weaknesses.join('、')}</TableCell>
                      </TableRow>
                      <TableRow>
                        <TableCell sx={{ fontWeight: 500 }}>关键产品</TableCell>
                        <TableCell>{(comp.keyProducts ?? []).join('、')}</TableCell>
                      </TableRow>
                    </TableBody>
                  </Table>
                </TableContainer>
              </Box>
            ))}
          </CardContent>
        </Card>
      )}

      {/* Footer */}
      <Box sx={{ textAlign: 'center', mt: 4, pt: 2, borderTop: '1px solid', borderColor: 'divider' }}>
        <Typography variant="caption" color="text.disabled">
          VOS 2.0 — AI 驱动的消费者洞察平台 | {brandName} · {reportType.title} · {today}
        </Typography>
      </Box>
    </Box>
  );
};

export default ReportPreview;
